package com.finance.tracker.transaction;
import com.finance.tracker.user.User; import jakarta.persistence.*; import java.math.BigDecimal; import java.time.LocalDate;
@Entity @Table(name="transactions") public class Transaction { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @ManyToOne(optional=false,fetch=FetchType.LAZY) @JoinColumn(name="user_id") private User user; @Enumerated(EnumType.STRING) @Column(nullable=false) private TransactionType type; @Column(nullable=false,precision=14,scale=2) private BigDecimal amount; @Column(nullable=false,length=80) private String category; @Column(length=500) private String description; @Column(nullable=false) private LocalDate date; public Long getId(){return id;} public User getUser(){return user;} public void setUser(User v){user=v;} public TransactionType getType(){return type;} public void setType(TransactionType v){type=v;} public BigDecimal getAmount(){return amount;} public void setAmount(BigDecimal v){amount=v;} public String getCategory(){return category;} public void setCategory(String v){category=v;} public String getDescription(){return description;} public void setDescription(String v){description=v;} public LocalDate getDate(){return date;} public void setDate(LocalDate v){date=v;} }
